package elftriage

import (
	"encoding/base64"
	"math"
	"math/rand"
	"strings"
	"testing"
)

// systemELF is a real gcc-built ELF: a stripped, dynamically-linked x86-64 PIE
// whose main calls getenv("X") then system(it) — a textbook backdoor shape.
// Ground truth from readelf: Type DYN, Machine x86-64, Entry 0x1080,
// NEEDED libc.so.6, interp /lib64/ld-linux-x86-64.so.2, imports system + getenv.
const systemELF = ""

func decode(t *testing.T, b64 string) *Result {
	t.Helper()
	raw := mustB64(t, b64)
	r, err := Decode(raw)
	if err != nil {
		t.Fatalf("Decode: %v", err)
	}
	return r
}

func TestDecode_SystemBackdoor(t *testing.T) {
	r := decode(t, systemELF)
	if r.Class != "ELFCLASS64" || r.Endianness != "little-endian" {
		t.Errorf("class=%q endian=%q", r.Class, r.Endianness)
	}
	if !strings.HasPrefix(r.Type, "DYN") || r.Machine != "x86-64" {
		t.Errorf("type=%q machine=%q", r.Type, r.Machine)
	}
	if r.EntryPoint != "0x1080" {
		t.Errorf("entry = %q, want 0x1080", r.EntryPoint)
	}
	if r.Interpreter != "/lib64/ld-linux-x86-64.so.2" || r.Static {
		t.Errorf("interp=%q static=%v", r.Interpreter, r.Static)
	}
	if !r.Stripped {
		t.Errorf("expected stripped=true")
	}
	if !contains(r.NeededLibraries, "libc.so.6") {
		t.Errorf("needed = %v", r.NeededLibraries)
	}
	if !contains(r.ImportedSymbols, "system") || !contains(r.ImportedSymbols, "getenv") {
		t.Errorf("imports = %v", r.ImportedSymbols)
	}
	if !contains(r.SuspiciousSymbols, "system") {
		t.Errorf("suspicious symbols = %v, want system", r.SuspiciousSymbols)
	}
	if !r.Suspicious || !strings.Contains(r.Note, "SUSPICIOUS") {
		t.Errorf("expected suspicious verdict: %+v", r.SuspiciousReasons)
	}
}

func TestDecode_Errors(t *testing.T) {
	for name, in := range map[string][]byte{
		"empty":  {},
		"no elf": []byte("MZ this is not an ELF"),
	} {
		if _, err := Decode(in); err == nil {
			t.Errorf("%s: expected error", name)
		}
	}
}

func TestEntropyExtremes(t *testing.T) {
	// All-zero data → entropy 0; uniformly distributed bytes → ~8.
	zero := make([]byte, 4096)
	if h := shannon(zero); h != 0 {
		t.Errorf("zero entropy = %f, want 0", h)
	}
	uni := make([]byte, 256*16)
	for i := range uni {
		uni[i] = byte(i % 256)
	}
	if h := shannon(uni); h < 7.99 {
		t.Errorf("uniform entropy = %f, want ~8", h)
	}
}

// shannon is a test helper mirroring the package's entropy math over a byte slice.
func shannon(data []byte) float64 {
	var counts [256]int
	for _, b := range data {
		counts[b]++
	}
	n := float64(len(data))
	var h float64
	for _, c := range counts {
		if c == 0 {
			continue
		}
		p := float64(c) / n
		h -= p * log2(p)
	}
	return h
}

func TestMachineName(t *testing.T) {
	// Spot-check the IoT-relevant architectures via the exported result.
	r := decode(t, systemELF)
	if r.Machine != "x86-64" {
		t.Errorf("machine = %q", r.Machine)
	}
}

func contains(xs []string, s string) bool {
	for _, x := range xs {
		if x == s {
			return true
		}
	}
	return false
}

func mustB64(t *testing.T, s string) []byte {
	t.Helper()
	b, err := b64decode(s)
	if err != nil {
		t.Fatalf("base64: %v", err)
	}
	return b
}

// TestDecode_MalformedNoPanic mutates a real ELF and asserts Decode never
// panics. The stdlib debug/elf parser slice-panics on crafted section/dynamic
// tables; Decode must recover and return an error instead of crashing the host.
// This test deliberately does NOT recover — if the guard regresses, a panic
// propagates and fails the run. A one-off 1M-mutation audit found 23 such
// panics in the unguarded parser (slice bounds out of range).
func TestDecode_MalformedNoPanic(t *testing.T) {
	seed := mustB64(t, systemELF)
	rng := rand.New(rand.NewSource(7))
	n := 60000
	if testing.Short() {
		n = 3000
	}
	for i := 0; i < n; i++ {
		m := make([]byte, len(seed))
		copy(m, seed)
		for k := 0; k < 1+rng.Intn(8); k++ {
			switch rng.Intn(5) {
			case 0:
				if len(m) > 0 {
					m[rng.Intn(len(m))] = byte(rng.Intn(256))
				}
			case 1:
				if len(m) >= 4 {
					o := rng.Intn(len(m) - 3)
					m[o], m[o+1], m[o+2], m[o+3] = byte(rng.Intn(256)), byte(rng.Intn(256)), byte(rng.Intn(256)), byte(rng.Intn(256))
				}
			case 2:
				if len(m) > 64 {
					o := rng.Intn(64)
					for j := o; j < o+4 && j < len(m); j++ {
						m[j] = 0xff
					}
				}
			case 3:
				m = append(m, make([]byte, rng.Intn(2048))...)
			case 4:
				if len(m) > 100 {
					m = m[:rng.Intn(len(m))]
				}
			}
		}
		_, _ = Decode(m) // must not panic — guard recovers internally
	}
}

func FuzzDecode(f *testing.F) {
	if b, err := b64decode(systemELF); err == nil {
		f.Add(b)
	}
	f.Add([]byte("\x7fELF"))
	f.Add([]byte{})
	f.Fuzz(func(_ *testing.T, in []byte) {
		_, _ = Decode(in)
	})
}

func b64decode(s string) ([]byte, error) { return base64.StdEncoding.DecodeString(s) }
func log2(x float64) float64             { return math.Log2(x) }
